&lt;ul data-end=&quot;1754&quot; data-start=&quot;262&quot;&gt;
	&lt;li data-end=&quot;424&quot; data-start=&quot;262&quot;&gt;
	&lt;p data-end=&quot;424&quot; data-start=&quot;264&quot;&gt;&lt;strong data-end=&quot;308&quot; data-start=&quot;264&quot;&gt;Union Minister of Textiles Giriraj Singh&lt;/strong&gt; unveiled a book titled &lt;strong data-end=&quot;422&quot; data-start=&quot;332&quot;&gt;&amp;quot;Carbon Footprint Assessment in the Indian Handloom Sector: Methods and Case Studies.&amp;quot;&lt;/strong&gt;&lt;/p&gt;
