		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1089&quot; data-start=&quot;1005&quot;&gt;
	&lt;p data-end=&quot;1089&quot; data-start=&quot;1007&quot;&gt;Emphasizes &lt;strong data-end=&quot;1059&quot; data-start=&quot;1018&quot;&gt;eco-conscious, low-emission practices&lt;/strong&gt; in &lt;strong data-end=&quot;1086&quot; data-start=&quot;1063&quot;&gt;handloom production&lt;/strong&gt;.&lt;/p&gt;
