		&lt;p data-end=&quot;1235&quot; data-start=&quot;1217&quot;&gt;&lt;strong data-end=&quot;1233&quot; data-start=&quot;1217&quot;&gt;Eco-friendly&lt;/strong&gt;&lt;/p&gt;
